206	function buildProcessSummary(process: Doc<'processes'>): ProcessSummary {
207	  return {
208	    processId: process._id,
209	    displayLabel: process.displayLabel,
210	    processType: process.processType,
211	    status: process.status,
212	    phaseLabel: process.phaseLabel,
213	    nextActionLabel: process.nextActionLabel,
214	    availableActions: deriveAvailableActions(process.status),
215	    hasEnvironment: process.hasEnvironment,
216	    updatedAt: process.updatedAt,
217	  };
218	}
219	
220	function deriveAvailableActions(status: ProcessStatus): ProcessAvailableAction[] {
221	  switch (status) {
222	    case 'draft':
223	      return ['open'];
224	    case 'running':
225	      return ['open', 'review'];
226	    case 'waiting':
227	      return ['respond'];
228	    case 'paused':
229	      return ['resume'];
230	    case 'completed':
231	      return ['review'];
232	    case 'failed':
233	      return ['review', 'restart'];
234	    case 'interrupted':
235	      return ['resume', 'review', 'rehydrate', 'restart'];
236	    default:
237	      return [];
238	  }
239	}
