241	async function transitionProcessToRunning(
242	  ctx: MutationCtx,
243	  processIdValue: string,
244	): Promise<{ process: ProcessSummary; currentRequest: CurrentProcessRequest | null }> {
245	  let processRecord: Doc<'processes'> | null = null;
246	
247	  try {
248	    processRecord = await ctx.db.get(processIdValue as Id<'processes'>);
249	  } catch {
250	    throw new Error('Process not found.');
251	  }
252	
253	  if (processRecord === null) {
254	    throw new Error('Process not found.');
255	  }
256	
257	  const now = new Date().toISOString();
258	  const nextProcessFields = {
259	    status: 'running' as const,
260	    phaseLabel: processRecord.phaseLabel === 'Draft' ? 'Working' : processRecord.phaseLabel,
261	    nextActionLabel: 'Monitor progress in the work surface',
262	    currentRequestHistoryItemId: null,
263	    updatedAt: now,
264	  };
265	
266	  await ctx.db.patch(processRecord._id, nextProcessFields);
267	
268	  try {
269	    await ctx.db.patch(processRecord.projectId as Id<'projects'>, {
270	      lastUpdatedAt: now,
271	      updatedAt: now,
272	    });
273	  } catch {
274	    // Keep the process transition durable even if the project lookup is stale.
275	  }
276	
277	  return {
278	    process: buildProcessSummary({
279	      ...processRecord,
280	      ...nextProcessFields,
281	    }),
282	    currentRequest: null,
283	  };
284	}

