201	  private updateProjectSummary(
202	    projectId: string,
203	    update: (project: ProjectSummary) => ProjectSummary,
204	  ): void {
205	    for (const [userId, projects] of this.projectsByUserId.entries()) {
206	      this.projectsByUserId.set(
207	        userId,
208	        projects.map((project) => (project.projectId === projectId ? update(project) : project)),
209	      );
210	    }
211	
212	    const direct = this.accessByProjectId.get(projectId);
213	    if (direct?.kind === 'accessible') {
214	      this.accessByProjectId.set(projectId, {
215	        kind: 'accessible',
216	        project: update(direct.project),
217	      });
218	    }
219	  }
220	
221	  private transitionProcessToRunning(processId: string): ProcessActionStoreResult {
222	    for (const [projectId, processes] of this.processesByProjectId.entries()) {
223	      const index = processes.findIndex((process) => process.processId === processId);
224	
225	      if (index === -1) {
226	        continue;
227	      }
228	
229	      const existing = processes[index];
230	
231	      if (existing === undefined) {
232	        continue;
233	      }
234	
235	      const now = new Date().toISOString();
236	      const nextProcess = processSummarySchema.parse({
237	        ...existing,
238	        status: 'running',
239	        phaseLabel: existing.phaseLabel === 'Draft' ? 'Working' : existing.phaseLabel,
240	        nextActionLabel: 'Monitor progress in the work surface',
241	        availableActions: ['open', 'review'],
242	        updatedAt: now,
243	      });
244	      const nextProcesses = [...processes];
245	      nextProcesses[index] = nextProcess;
246	      this.processesByProjectId.set(projectId, nextProcesses);
247	
248	      return {
249	        process: nextProcess,
250	        currentRequest: null,
251	      };
252	    }
253	
254	    throw new Error(`Unknown process ${processId}`);
255	  }
256	}
